import { supabase } from './supabaseClient';
import { Role, User, Account, StockProduct, StockProductWithDetails, StudentStock, SavingsProduct, StudentSaving, Job, TaxItemWithRecipients, StockHistory, Fund, FundInvestment, FundStatus } from '../types';

const handleSupabaseError = (error: any, context: string) => {
    if (error) {
        console.error(`Error in ${context}:`, error);
        if (error.code === 'PGRST202' || error.message.includes('Could not find the function')) {
             throw new Error(`Supabase에 해당 함수가 없습니다. (${context})`);
        }
        if (error.code === '42501' || error.message.includes('permission denied')) {
             throw new Error('권한이 없습니다 (RLS Error).');
        }
        throw new Error(error.message || `An error occurred during ${context}.`);
    }
};

const uuidv4 = () => {
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
        var r = Math.random() * 16 | 0, v = c == 'x' ? r : (r & 0x3 | 0x8);
        return v.toString(16);
    });
};

const login = async (userId: string): Promise<User | null> => {
    const { data, error } = await supabase.from('users').select('*').eq('userId', userId).single();
    handleSupabaseError(error, 'login');
    return data;
};

const loginWithPassword = async (grade: number, classNum: number, number: number, password: string): Promise<User | null> => {
    const { data, error } = await supabase.rpc('login_with_password', { p_grade: grade, p_class: classNum, p_number: number, p_password: password });
    if (error) throw new Error(error.message);
    if (!data.success) throw new Error(data.message);
    return data.user as User;
};

const changePassword = async (userId: string, current: string, newPw: string): Promise<string> => {
    const { data, error } = await supabase.rpc('change_password', { p_user_id: userId, p_current_password: current, p_new_password: newPw });
    if (error) throw new Error(error.message);
    return data;
};

const resetPassword = async (userId: string): Promise<void> => {
    const { error } = await supabase.rpc('reset_password', { p_user_id: userId });
    if (error) throw new Error(error.message);
};

const loginWithQrToken = async (token: string): Promise<User | null> => {
    const { data: accountData, error: accountError } = await supabase.from('accounts').select('userId').eq('qrToken', token).single();
    handleSupabaseError(accountError, 'loginWithQrToken');
    if (!accountData) return null;
    return login(accountData.userId);
};

const getUsersByRole = async (role: Role): Promise<User[]> => {
    const { data, error } = await supabase.from('users').select('*').eq('role', role);
    handleSupabaseError(error, `getUsersByRole (${role})`);
    return data || [];
};

const addStudent = async (name: string, grade: number, classNum: number, number: number): Promise<void> => {
    const userId = uuidv4();
    const { error } = await supabase.rpc('add_student', { p_user_id: userId, p_name: name, p_grade: grade, p_class: classNum, p_number: number });
    handleSupabaseError(error, 'addStudent');
};

const deleteStudents = async (userIds: string[]): Promise<string> => {
    let successCount = 0;
    for (const userId of userIds) {
        try { const { error } = await supabase.rpc('delete_student', { p_user_id: userId }); if (error) throw error; successCount++; } catch (e) { console.error(e); }
    }
    return `${successCount}명의 학생을 삭제했습니다.`;
};

const getStudentAccountByUserId = async (userId: string): Promise<Account | null> => {
    const { data, error } = await supabase.from('accounts').select('*').eq('userId', userId).single();
    if (error && error.code !== 'PGRST116') handleSupabaseError(error, 'getStudentAccountByUserId');
    return data;
};

const getTeacherAccount = async (): Promise<Account | null> => {
    const { data: users } = await supabase.from('users').select('userId').eq('role', 'teacher').limit(1);
    if (!users || users.length === 0) return null;
    const { data: account } = await supabase.from('accounts').select('*').eq('userId', users[0].userId).single();
    return account;
};

const getTransactionsByAccountId = async (accountId: string): Promise<any[]> => {
