        fetchProducts();
    }, [fetchProducts]);

    const handleSelectForDelete = (productId: string) => {
        setProductsToDelete(prev => 
            prev.includes(productId) ? prev.filter(id => id !== productId) : [...prev, productId]
        );
    };

