                            }} />
                            <span>{s.name}</span>
                        </label>
                    ))}
                </div>
                <button onClick={handleSubmit} className="w-full p-3 bg-blue-600 text-white font-bold rounded-lg">고지하기</button>
                <button onClick={onClose} className="w-full p-2 mt-2 text-gray-500">취소</button>
            </div>
        </div>
    );
};

