                            <div className="p-3 bg-gray-50 border-t flex gap-2">
                                <button onClick={() => setSettleModal({ isOpen: true, fund })} className="w-full py-2 bg-indigo-600 text-white font-bold rounded-lg hover:bg-indigo-700 text-sm">
