const AddFundModal: React.FC<{ students: (User & { account: Account | null })[], onClose: () => void, onComplete: () => void }> = ({ students, onClose, onComplete }) => {
    const [formData, setFormData] = useState({
        name: '', description: '', creatorId: '', unitPrice: 1000, targetAmount: 100000,
        baseReward: 100, incentiveReward: 200, recruitmentDeadline: '', maturityDate: ''
    });
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');
    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: ['unitPrice', 'targetAmount', 'baseReward', 'incentiveReward'].includes(name) ? parseInt(value) || 0 : value }));
    };
    const handleSubmit = async () => {
        if (Object.values(formData).some(v => v === '' || v === 0)) { setError('모든 항목을 입력해주세요.'); return; }
        setLoading(true);
        try { await api.createFund(formData); onComplete(); onClose(); }
        catch (err: any) { setError(err.message); }
        finally { setLoading(false); }
    };
    return (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-xl shadow-2xl p-6 w-full max-w-lg max-h-[90vh] overflow-y-auto">
                <div className="flex justify-between items-center mb-4">
                    <h3 className="text-xl font-bold">새 펀드 개설</h3>
                    <button onClick={onClose} className="p-1 rounded-full hover:bg-gray-200"><XIcon className="w-6 h-6 text-gray-600" /></button>
                </div>
                <div className="space-y-3 text-sm">
                    <input type="text" name="name" value={formData.name} onChange={handleChange} className="w-full p-2 border rounded" placeholder="펀드명"/>
                    <textarea name="description" value={formData.description} onChange={handleChange} className="w-full p-2 border rounded h-20" placeholder="내용"/>
                    <select name="creatorId" value={formData.creatorId} onChange={handleChange} className="w-full p-2 border rounded bg-white">
                        <option value="">제안 학생 선택</option>
                        {students.map(s => <option key={s.userId} value={s.userId}>{s.name}</option>)}
                    </select>
                </div>
                {error && <p className="text-red-500 text-sm mt-4">{error}</p>}
                <button onClick={handleSubmit} disabled={loading} className="mt-6 w-full p-3 bg-indigo-600 text-white font-bold rounded-lg shadow-md">개설하기</button>
            </div>
        </div>
    );
};

