                                    <span>평가일</span>
                                    <span className="text-blue-600">{inv.fund?.maturityDate ? new Date(inv.fund.maturityDate).toLocaleDateString() : '-'}</span>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            )}

