                            </div>
                            <div className="flex justify-between text-sm text-gray-600 mt-1">
                                <span>모집 마감</span>
                                <span>{new Date(f.recruitmentDeadline).toLocaleDateString()}</span>
                            </div>
                            <div className="flex justify-between text-sm text-gray-600 mt-1">
