                    </label>
                    {students.map(s => (
                        <label key={s.userId} className="flex items-center space-x-2 text-sm">
                            <input type="checkbox" checked={selectedIds.includes(s.userId)} onChange={(e) => {
                                if(e.target.checked) setSelectedIds([...selectedIds, s.userId]);
