    handleSupabaseError(error, 'getStudentStocks');

    if (!data) return [];

    return data.map(ss => {
        const stock = ss.stock_products as StockProduct;
        delete (ss as any).stock_products;
        return { ...ss, stock } as StudentStock;
    });
