### 3. Supabase SQL Editor용 쿼리 (통합본)

아래 쿼리를 Supabase의 **SQL Editor**에 복사하여 붙여넣고 실행하세요. 이 쿼리는 안전장치가 완비된 새로운 주식 거래 로직을 생성합니다.

```sql
-- 1. 주식 매수 함수 (buy_stock) 업데이트
CREATE OR REPLACE FUNCTION public.buy_stock(p_user_id uuid, p_stock_id uuid, p_quantity integer)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_account_id text;
    v_balance bigint;
    v_old_price bigint;
    v_new_price bigint;
    v_exec_price bigint;
    v_total_cost bigint;
    v_stock_name text;
    v_volatility numeric;
    v_daily_total integer;
BEGIN
    -- 1. 기본 정보 조회
    SELECT "accountId", balance INTO v_account_id, v_balance FROM public.accounts WHERE "userId" = p_user_id;
    SELECT "currentPrice", name, COALESCE(volatility, 0.01) INTO v_old_price, v_stock_name, v_volatility FROM public.stock_products WHERE id = p_stock_id;

    -- 2. 1일 거래량 한도 체크 (100주)
    -- 설명문에 포함된 수량 정보를 정규식으로 추출하여 합산
    SELECT COALESCE(SUM(CAST(SUBSTRING(description FROM '([0-9]+)주') AS INTEGER)), 0)
    INTO v_daily_total
    FROM public.transactions
    WHERE "accountId" = v_account_id 
      AND type IN ('StockBuy', 'StockSell') 
      AND date::date = CURRENT_DATE;

    IF (v_daily_total + p_quantity) > 100 THEN
        RAISE EXCEPTION '하루 최대 거래량(100주)을 초과할 수 없습니다. (현재 오늘 거래량: %주)', v_daily_total;
    END IF;

    -- 3. 지수 모델 가격 계산: P_new = P_old * e^(k * Q)
    v_new_price := floor(v_old_price * exp(v_volatility * p_quantity));

    -- 4. 안전장치: 1회 변동폭 최대 30% 제한
    IF v_new_price > floor(v_old_price * 1.3) THEN
        v_new_price := floor(v_old_price * 1.3);
    END IF;

    -- 5. 슬리피지 적용: 평균체결가 = (전가 + 후가) / 2
    v_exec_price := (v_old_price + v_new_price) / 2;
    v_total_cost := v_exec_price * p_quantity;

    -- 6. 잔액 체크
    IF v_balance < v_total_cost THEN
        RAISE EXCEPTION '잔액이 부족합니다. (필요 금액: %권, 현재 잔액: %권)', v_total_cost, v_balance;
    END IF;

    -- 7. 거래 처리
    -- 계좌 차감
    UPDATE public.accounts SET balance = balance - v_total_cost WHERE "accountId" = v_account_id;

    -- 주가 업데이트
    UPDATE public.stock_products SET "currentPrice" = v_new_price WHERE id = p_stock_id;

    -- 가격 히스토리 기록
    INSERT INTO public.stock_price_history ("stockId", price) VALUES (p_stock_id, v_new_price);

    -- 거래 내역 기록 (수량 정보를 정규식으로 읽을 수 있도록 포맷 고정)
    INSERT INTO public.transactions ("transactionId", "accountId", type, amount, date, description)
    VALUES (gen_random_uuid(), v_account_id, 'StockBuy', -v_total_cost, now(), 
            format('[주식매수] %s %s주 (평균체결가: %s권)', v_stock_name, p_quantity, v_exec_price));

    -- 보유 주식 업데이트
    INSERT INTO public.student_stocks ("userId", "stockId", quantity, "purchasePrice")
    VALUES (p_user_id, p_stock_id, p_quantity, v_exec_price)
    ON CONFLICT ("userId", "stockId") DO UPDATE SET
        "purchasePrice" = (public.student_stocks.quantity * public.student_stocks."purchasePrice" + v_total_cost) / (public.student_stocks.quantity + p_quantity),
        quantity = public.student_stocks.quantity + p_quantity;
END;
$function$;

-- 2. 주식 매도 함수 (sell_stock) 업데이트
CREATE OR REPLACE FUNCTION public.sell_stock(p_user_id uuid, p_stock_id uuid, p_quantity integer)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_account_id text;
    v_owned_quantity integer;
    v_old_price bigint;
    v_new_price bigint;
    v_exec_price bigint;
    v_gross_amount bigint;
    v_tax_amount bigint;
    v_net_amount bigint;
    v_stock_name text;
    v_volatility numeric;
    v_daily_total integer;
BEGIN
    -- 1. 기본 정보 조회
    SELECT "accountId" INTO v_account_id FROM public.accounts WHERE "userId" = p_user_id;
    SELECT quantity INTO v_owned_quantity FROM public.student_stocks WHERE "userId" = p_user_id AND "stockId" = p_stock_id;
    SELECT "currentPrice", name, COALESCE(volatility, 0.01) INTO v_old_price, v_stock_name, v_volatility FROM public.stock_products WHERE id = p_stock_id;

    -- 2. 유효성 체크
    IF v_owned_quantity IS NULL OR v_owned_quantity < p_quantity THEN
        RAISE EXCEPTION '보유 수량이 부족합니다.';
    END IF;

    -- 3. 1일 거래량 한도 체크 (100주)
    SELECT COALESCE(SUM(CAST(SUBSTRING(description FROM '([0-9]+)주') AS INTEGER)), 0)
    INTO v_daily_total
    FROM public.transactions
    WHERE "accountId" = v_account_id 
      AND type IN ('StockBuy', 'StockSell') 
      AND date::date = CURRENT_DATE;

    IF (v_daily_total + p_quantity) > 100 THEN
        RAISE EXCEPTION '하루 최대 거래량(100주)을 초과할 수 없습니다. (현재 오늘 거래량: %주)', v_daily_total;
    END IF;

    -- 4. 지수 모델 가격 계산: P_new = P_old * e^(-k * Q)
    v_new_price := floor(v_old_price * exp(-v_volatility * p_quantity));

    -- 5. 안전장치: 1회 변동폭 최대 30% 제한
    IF v_new_price < floor(v_old_price * 0.7) THEN
        v_new_price := floor(v_old_price * 0.7);
    END IF;

    -- 6. 슬리피지 적용: 평균체결가 = (전가 + 후가) / 2
    v_exec_price := (v_old_price + v_new_price) / 2;
    v_gross_amount := v_exec_price * p_quantity;

    -- 7. 매도 수수료(세금) 1% 적용
    v_tax_amount := floor(v_gross_amount * 0.01);
    v_net_amount := v_gross_amount - v_tax_amount;

    -- 8. 거래 처리
    -- 계좌 입금
    UPDATE public.accounts SET balance = balance + v_net_amount WHERE "accountId" = v_account_id;

    -- 주가 업데이트
    UPDATE public.stock_products SET "currentPrice" = v_new_price WHERE id = p_stock_id;

    -- 가격 히스토리 기록
    INSERT INTO public.stock_price_history ("stockId", price) VALUES (p_stock_id, v_new_price);

    -- 거래 내역 기록
    INSERT INTO public.transactions ("transactionId", "accountId", type, amount, date, description)
    VALUES (gen_random_uuid(), v_account_id, 'StockSell', v_net_amount, now(), 
            format('[주식매도] %s %s주 (체결가: %s권, 세금: %s권)', v_stock_name, p_quantity, v_exec_price, v_tax_amount));

    -- 보유 수량 차감
    UPDATE public.student_stocks 
    SET quantity = quantity - p_quantity 
    WHERE "userId" = p_user_id AND "stockId" = p_stock_id;

    -- 수량이 0이면 레코드 삭제
    DELETE FROM public.student_stocks WHERE "userId" = p_user_id AND "stockId" = p_stock_id AND quantity <= 0;

    RETURN format('%s주를 평균 %s원에 판매했습니다. (세금 1%% 제외 %s원 입금)', p_quantity, v_exec_price, v_net_amount);
END;
$function$;

이 문제는 Supabase(Postgres) 내에 동일한 이름을 가졌으나 매개변수 타입이 다른 함수가 중복으로 존재할 때 발생합니다. `CREATE OR REPLACE`는 **매개변수 타입까지 완벽히 일치해야 덮어쓰기**를 수행하며, 타입이 다르면(예: `text` vs `uuid`) 새로운 함수를 추가로 생성(오버로딩)해버립니다.

따라서 Supabase가 어떤 함수를 실행해야 할지 몰라 "Could not choose the best candidate" 에러를 내뱉는 것입니다. 이를 해결하기 위해 **기존의 모든 중복 함수를 삭제(DROP)한 후, 명확한 타입으로 다시 생성**해야 합니다.

### 1. 이전 쿼리 처리 및 해결 방법 안내
*   **원인**: 이전 작업 중 `text` 타입 매개변수를 사용하는 함수와 `uuid` 타입을 사용하는 함수가 동시에 생성되어 충돌이 발생했습니다.
*   **해결책**: 아래 제공되는 SQL 쿼리 상단에는 `DROP FUNCTION IF EXISTS` 구문이 포함되어 있습니다. 이 구문이 중복된 함수 후보들을 모두 깨끗하게 지워준 후, 단 하나의 올바른 함수(UUID 기반)만 남게 됩니다.
*   **방법**: 아래 SQL 코드를 복사하여 Supabase **SQL Editor**에 붙여넣고 **Run** 버튼을 누르세요.

---

