        studentUserId: inv.student_user_id,
        units: inv.units,
        investedAt: inv.invested_at,
        fund: inv.funds ? {
             ...inv.funds,
            creatorId: inv.funds.creator_student_id,
            teacherId: inv.funds.teacher_id,
