사용자님, 주식 매수/매도 시 발생하는 "함수 매개변수 불일치" 에러는 Supabase(Postgres) 엔진이 클라이언트(앱)에서 보낸 데이터 타입과 데이터베이스에 저장된 함수의 정의를 연결하지 못할 때 발생합니다. 

현재 상황에서 사용자님의 DB 스키마 정보를 바탕으로 분석한 결과, **가장 확실한 해결책은 기존에 생성된 모든 버전의 함수를 강제로 삭제하고, `text` 타입을 기본으로 하는 단 하나의 함수로 재설정**하는 것입니다.

### 1. Supabase SQL Editor에서 실행할 해결 쿼리 (필독)

이 쿼리는 이전에 발생했던 모든 타입 충돌(UUID vs TEXT)과 후보 함수 누락 문제를 완벽히 해결합니다. **Supabase SQL Editor에 복사하여 실행해 주세요.**

```sql
-- 1. 기존의 모든 중복/충돌 가능성이 있는 함수 삭제 (타입별 명시적 삭제)
DROP FUNCTION IF EXISTS public.buy_stock(p_user_id uuid, p_stock_id uuid, p_quantity integer);
DROP FUNCTION IF EXISTS public.buy_stock(p_user_id text, p_stock_id text, p_quantity integer);
DROP FUNCTION IF EXISTS public.buy_stock(p_user_id uuid, p_stock_id text, p_quantity integer);

DROP FUNCTION IF EXISTS public.sell_stock(p_user_id uuid, p_stock_id uuid, p_quantity integer);
DROP FUNCTION IF EXISTS public.sell_stock(p_user_id text, p_stock_id text, p_quantity integer);
DROP FUNCTION IF EXISTS public.sell_stock(p_user_id uuid, p_stock_id text, p_quantity integer);

-- 2. 매수 함수 재생성 (매개변수 타입을 TEXT로 고정하여 앱의 string 데이터와 1:1 매칭)
CREATE OR REPLACE FUNCTION public.buy_stock(p_user_id text, p_stock_id text, p_quantity integer)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_account_id text;
    v_balance bigint;
    v_old_price bigint;
    v_new_price bigint;
    v_exec_price bigint;
    v_total_cost bigint;
    v_stock_name text;
    v_volatility numeric;
    v_daily_total integer;
BEGIN
    -- 1. 기본 정보 조회 (p_user_id는 uuid로 캐스팅하여 accounts 조회)
    SELECT "accountId", balance INTO v_account_id, v_balance FROM public.accounts WHERE "userId" = p_user_id::uuid;
    -- stock_products.id는 text이므로 그대로 비교
    SELECT "currentPrice", name, COALESCE(volatility, 0.01) INTO v_old_price, v_stock_name, v_volatility FROM public.stock_products WHERE id = p_stock_id;

    -- 2. 1일 거래량 한도 체크 (100주)
    SELECT COALESCE(SUM(CAST(SUBSTRING(description FROM '([0-9]+)주') AS INTEGER)), 0)
    INTO v_daily_total
    FROM public.transactions
    WHERE "accountId" = v_account_id 
      AND type IN ('StockBuy', 'StockSell') 
      AND date::date = CURRENT_DATE;

    IF (v_daily_total + p_quantity) > 100 THEN
        RAISE EXCEPTION '하루 최대 거래량(100주)을 초과할 수 없습니다. (현재 오늘 거래량: %주)', v_daily_total;
    END IF;

    -- 3. 지수 모델 가격 계산 및 30% 상한선
    v_new_price := floor(v_old_price * exp(v_volatility * p_quantity));
    IF v_new_price > floor(v_old_price * 1.3) THEN v_new_price := floor(v_old_price * 1.3); END IF;

    -- 4. 슬리피지(평균체결가) 적용
    v_exec_price := (v_old_price + v_new_price) / 2;
    v_total_cost := v_exec_price * p_quantity;

    -- 5. 잔액 체크
    IF v_balance < v_total_cost THEN
        RAISE EXCEPTION '잔액이 부족합니다. (필요 금액: %권, 현재 잔액: %권)', v_total_cost, v_balance;
    END IF;

    -- 6. 거래 처리
    UPDATE public.accounts SET balance = balance - v_total_cost WHERE "accountId" = v_account_id;
    UPDATE public.stock_products SET "currentPrice" = v_new_price WHERE id = p_stock_id;

    -- stock_price_history.stockId는 text이므로 그대로 입력
    INSERT INTO public.stock_price_history ("stockId", price) VALUES (p_stock_id, v_new_price);

    INSERT INTO public.transactions ("transactionId", "accountId", type, amount, date, description)
    VALUES (gen_random_uuid(), v_account_id, 'StockBuy', -v_total_cost, now(), 
            format('[주식매수] %s %s주 (평균체결가: %s권)', v_stock_name, p_quantity, v_exec_price));

    INSERT INTO public.student_stocks ("userId", "stockId", quantity, "purchasePrice")
    VALUES (p_user_id::uuid, p_stock_id, p_quantity, v_exec_price)
    ON CONFLICT ("userId", "stockId") DO UPDATE SET
        "purchasePrice" = (public.student_stocks.quantity * public.student_stocks."purchasePrice" + v_total_cost) / (public.student_stocks.quantity + p_quantity),
        quantity = public.student_stocks.quantity + p_quantity;
END;
$function$;

-- 3. 매도 함수 재생성
CREATE OR REPLACE FUNCTION public.sell_stock(p_user_id text, p_stock_id text, p_quantity integer)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_account_id text;
    v_owned_quantity integer;
    v_old_price bigint;
    v_new_price bigint;
    v_exec_price bigint;
    v_gross_amount bigint;
    v_tax_amount bigint;
    v_net_amount bigint;
    v_stock_name text;
    v_volatility numeric;
    v_daily_total integer;
BEGIN
    -- 1. 기본 정보 조회
    SELECT "accountId" INTO v_account_id FROM public.accounts WHERE "userId" = p_user_id::uuid;
    SELECT quantity INTO v_owned_quantity FROM public.student_stocks WHERE "userId" = p_user_id::uuid AND "stockId" = p_stock_id;
    SELECT "currentPrice", name, COALESCE(volatility, 0.01) INTO v_old_price, v_stock_name, v_volatility FROM public.stock_products WHERE id = p_stock_id;

    -- 2. 유효성 체크
    IF v_owned_quantity IS NULL OR v_owned_quantity < p_quantity THEN
        RAISE EXCEPTION '보유 수량이 부족합니다.';
    END IF;

    -- 3. 1일 거래량 한도 체크
    SELECT COALESCE(SUM(CAST(SUBSTRING(description FROM '([0-9]+)주') AS INTEGER)), 0)
    INTO v_daily_total
    FROM public.transactions
    WHERE "accountId" = v_account_id 
      AND type IN ('StockBuy', 'StockSell') 
      AND date::date = CURRENT_DATE;

    IF (v_daily_total + p_quantity) > 100 THEN
        RAISE EXCEPTION '하루 최대 거래량(100주)을 초과할 수 없습니다. (현재 오늘 거래량: %주)', v_daily_total;
    END IF;

    -- 4. 지수 모델 가격 계산 및 30% 하한선
    v_new_price := floor(v_old_price * exp(-v_volatility * p_quantity));
    IF v_new_price < floor(v_old_price * 0.7) THEN v_new_price := floor(v_old_price * 0.7); END IF;

    -- 5. 슬리피지 적용 및 매도 세금(1%) 계산
    v_exec_price := (v_old_price + v_new_price) / 2;
    v_gross_amount := v_exec_price * p_quantity;
    v_tax_amount := floor(v_gross_amount * 0.01);
    v_net_amount := v_gross_amount - v_tax_amount;

    -- 6. 거래 처리
    UPDATE public.accounts SET balance = balance + v_net_amount WHERE "accountId" = v_account_id;
    UPDATE public.stock_products SET "currentPrice" = v_new_price WHERE id = p_stock_id;
    INSERT INTO public.stock_price_history ("stockId", price) VALUES (p_stock_id, v_new_price);

    INSERT INTO public.transactions ("transactionId", "accountId", type, amount, date, description)
    VALUES (gen_random_uuid(), v_account_id, 'StockSell', v_net_amount, now(), 
            format('[주식매도] %s %s주 (체결가: %s권, 세금: %s권)', v_stock_name, p_quantity, v_exec_price, v_tax_amount));

    UPDATE public.student_stocks 
    SET quantity = quantity - p_quantity 
    WHERE "userId" = p_user_id::uuid AND "stockId" = p_stock_id;

    DELETE FROM public.student_stocks WHERE "userId" = p_user_id::uuid AND "stockId" = p_stock_id AND quantity <= 0;

    RETURN format('%s주를 평균 %s원에 판매했습니다. (세금 1%% 제외 %s원 입금)', p_quantity, v_exec_price, v_net_amount);
END;
$function$;
```

### 2. 코드 업데이트 사항
매개변수 이름을 명시적으로 맞춰서 전달하도록 `services/api.ts`를 다시 한번 정리했습니다.

