            const message = await api.cancelSavings(currentUser.userId, cancelTargetId);
            showNotification('success', message);
            fetchData();
            refreshAccount();
        } catch(e: any) { 
            showNotification('error', e.message); 
        }
        finally { setCancelTargetId(null); }
