                                        </div>
                                        <div className="flex flex-col">
                                            <span className="text-xs text-gray-400 mb-1 font-medium">만기 예정일</span>
                                            <span className="font-bold text-blue-600">{new Date(s.maturityDate).toLocaleDateString()}</span>
