                <input 
                    type="number" 
                    value={amount} 
                    onChange={e => setAmount(e.target.value)} 
                    placeholder={`최대 ${product.maxAmount}권`}
                    className="w-full p-3 border rounded-lg mb-4"
                />

                <button 
                    onClick={() => {
                        const val = parseInt(amount);
