payload.text:
아이디와 비밀번호를 통한 학생 로그인은 물론, 주식 거래 시의 동적 수수료 계산까지 모든 로직이 잘 구축되어 있습니다.

학생 페이지의 주식 매수/매도 팝업(상세 모달)의 세로 길이를 **기존 90vh에서 99vh(약 10% 증가)**로 조정하여 하단 버튼이 가려지지 않도록 수정하였습니다. 또한 문의하신 SQL 쿼리에 대해서도 답변해 드립니다.

### Supabase SQL 관련 답변
네, 맞습니다. **이전에 입력했던 `buy_stock` 및 `sell_stock` 관련 SQL 코드를 모두 삭제(DROP)하고 새로운 코드를 입력하는 것이 가장 안전합니다.** 

타입(UUID vs TEXT)이 다른 중복 함수들이 남아있을 경우 "함수 매개변수 불일치" 에러가 발생할 수 있기 때문입니다. 아래 제공해 드리는 쿼리는 기존의 모든 중복 가능성을 제거하고 정확히 `TEXT` 타입 ID를 사용하는 최신 로직만 남기도록 설계되었습니다.

---

### 1. Supabase SQL Editor 실행 쿼리
아래 쿼리를 복사하여 Supabase SQL Editor에서 실행해 주세요.

```sql
-- 1. 기존에 존재할 수 있는 모든 중복 함수를 명시적으로 삭제 (에러 방지)
DROP FUNCTION IF EXISTS public.buy_stock(p_user_id uuid, p_stock_id uuid, p_quantity integer);
DROP FUNCTION IF EXISTS public.buy_stock(p_user_id text, p_stock_id text, p_quantity integer);
DROP FUNCTION IF EXISTS public.buy_stock(p_user_id uuid, p_stock_id text, p_quantity integer);

DROP FUNCTION IF EXISTS public.sell_stock(p_user_id uuid, p_stock_id uuid, p_quantity integer);
DROP FUNCTION IF EXISTS public.sell_stock(p_user_id text, p_stock_id text, p_quantity integer);
DROP FUNCTION IF EXISTS public.sell_stock(p_user_id uuid, p_stock_id text, p_quantity integer);

-- 2. 매수 함수 (수수료 0%)
CREATE OR REPLACE FUNCTION public.buy_stock(p_user_id text, p_stock_id text, p_quantity integer)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_account_id text;
    v_balance bigint;
    v_old_price bigint;
    v_new_price bigint;
    v_exec_price bigint;
    v_total_cost bigint;
    v_stock_name text;
    v_volatility numeric;
BEGIN
    SELECT "accountId", balance INTO v_account_id, v_balance FROM public.accounts WHERE "userId" = p_user_id;
    SELECT "currentPrice", name, COALESCE(volatility, 0.01) INTO v_old_price, v_stock_name, v_volatility FROM public.stock_products WHERE id = p_stock_id;

    v_new_price := floor(v_old_price * exp(v_volatility * p_quantity));
    v_exec_price := (v_old_price + v_new_price) / 2;
    v_total_cost := v_exec_price * p_quantity;

    IF v_balance < v_total_cost THEN
        RAISE EXCEPTION '잔액이 부족합니다. (필요: %권, 잔액: %권)', v_total_cost, v_balance;
    END IF;

    UPDATE public.accounts SET balance = balance - v_total_cost WHERE "accountId" = v_account_id;
    UPDATE public.stock_products SET "currentPrice" = v_new_price WHERE id = p_stock_id;
    INSERT INTO public.stock_price_history ("stockId", price) VALUES (p_stock_id, v_new_price);

    INSERT INTO public.transactions ("transactionId", "accountId", type, amount, date, description)
    VALUES (gen_random_uuid(), v_account_id, 'StockBuy', -v_total_cost, now(), format('[주식매수] %s %s주 (체결가: %s, 수수료 0%%)', v_stock_name, p_quantity, v_exec_price));

    INSERT INTO public.student_stocks ("userId", "stockId", quantity, "purchasePrice")
    VALUES (p_user_id, p_stock_id, p_quantity, v_exec_price)
    ON CONFLICT ("userId", "stockId") DO UPDATE SET
        "purchasePrice" = (public.student_stocks.quantity * public.student_stocks."purchasePrice" + v_total_cost) / (public.student_stocks.quantity + p_quantity),
        quantity = public.student_stocks.quantity + p_quantity;
END;
$function$;

-- 3. 매도 함수 (동적 수수료 적용)
CREATE OR REPLACE FUNCTION public.sell_stock(p_user_id text, p_stock_id text, p_quantity integer)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_account_id text;
    v_owned_quantity integer;
    v_old_price bigint;
    v_new_price bigint;
    v_exec_price bigint;
    v_total_sell_val bigint;
    v_price_impact_pct numeric;
    v_fee_rate numeric;
    v_fee_amount bigint;
    v_net_amount bigint;
    v_stock_name text;
    v_volatility numeric;
BEGIN
    SELECT "accountId" INTO v_account_id FROM public.accounts WHERE "userId" = p_user_id;
    SELECT quantity INTO v_owned_quantity FROM public.student_stocks WHERE "userId" = p_user_id AND "stockId" = p_stock_id;
    SELECT "currentPrice", name, COALESCE(volatility, 0.01) INTO v_old_price, v_stock_name, v_volatility FROM public.stock_products WHERE id = p_stock_id;

    IF v_owned_quantity IS NULL OR v_owned_quantity < p_quantity THEN
        RAISE EXCEPTION '보유 수량이 부족합니다.';
    END IF;

    v_new_price := floor(v_old_price * exp(-v_volatility * p_quantity));
    v_exec_price := (v_old_price + v_new_price) / 2;
    v_total_sell_val := v_exec_price * p_quantity;

    v_price_impact_pct := ((v_old_price - v_new_price)::numeric / v_old_price::numeric) * 100;
    v_fee_rate := (v_price_impact_pct * 1.05) + 2.0;

    IF v_fee_rate < 2.0 THEN v_fee_rate := 2.0; END IF;
    IF v_fee_rate > 33.5 THEN v_fee_rate := 33.5; END IF;

    v_fee_amount := floor(v_total_sell_val * (v_fee_rate / 100.0));
    v_net_amount := v_total_sell_val - v_fee_amount;

    UPDATE public.accounts SET balance = balance + v_net_amount WHERE "accountId" = v_account_id;
    UPDATE public.stock_products SET "currentPrice" = v_new_price WHERE id = p_stock_id;
    INSERT INTO public.stock_price_history ("stockId", price) VALUES (p_stock_id, v_new_price);

    INSERT INTO public.transactions ("transactionId", "accountId", type, amount, date, description)
    VALUES (gen_random_uuid(), v_account_id, 'StockSell', v_net_amount, now(), 
            format('[주식매도] %s %s주 (체결가: %s, 수수료 %s%%: %s권)', v_stock_name, p_quantity, v_exec_price, round(v_fee_rate, 1), v_fee_amount));

    UPDATE public.student_stocks SET quantity = quantity - p_quantity WHERE "userId" = p_user_id AND "stockId" = p_stock_id;
    DELETE FROM public.student_stocks WHERE "userId" = p_user_id AND "stockId" = p_stock_id AND quantity <= 0;

    RETURN format('%s주 판매 완료. 수수료 %s%%(%s권) 제외 후 %s권 입금.', p_quantity, round(v_fee_rate, 1), v_fee_amount, v_net_amount);
END;
$function$;
```

### 2. 프론트엔드 코드 업데이트

