                            <div className="flex justify-between text-sm text-gray-600 mt-1">
                                <span>기간</span>
                                <span>{p.maturityDays}일</span>
                            </div>
                        </div>
                    ))}
                </div>
            </div>

            {selectedProduct && (
                <JoinSavingsModal 
                    product={selectedProduct} 
                    onClose={() => setSelectedProduct(null)} 
