                className="w-full mt-8 p-4 bg-indigo-600 text-white font-bold rounded-xl shadow-lg hover:bg-indigo-700 disabled:bg-gray-300 disabled:shadow-none transition-all active:scale-95"
            >
                {loading ? '송금 중...' : '보내기'}
            </button>
        </div>
    );
};

