    // PostgREST는 UUID 타입에 대해 문자열을 자동으로 변환하려 시도하므로, 
    // 매개변수 이름을 p_stock_id로 정확히 일치시키는 것이 중요합니다.
    const { error } = await supabase.rpc('rpc_update_stock_price_final', {
