const deleteJobs = async (jobIds: string[]): Promise<string> => {
    let successCount = 0;
    const errors: string[] = [];
    console.log("Deleting jobs:", jobIds);
    for (const jobId of jobIds) {
        try {
            const { error } = await supabase.rpc('delete_job', { p_job_id: jobId });
            if (error) throw error;
            successCount++;
        } catch (error: any) {
            errors.push(jobId);
        }
