        .eq('student_user_id', userId)
        .eq('is_paid', false);
    handleSupabaseError(error, 'getMyUnpaidTaxes');
    return data.map((r: any) => ({
        recipientId: r.id,
        taxId: r.tax_id,
        name: r.tax_items.name,
        amount: r.tax_items.amount,
        dueDate: r.tax_items.due_date
    }));
};

